-- Sprint 11 — Catálogo de indicadores nativos e disponibilidade automática
create table if not exists public.native_indicator_definitions (
 id uuid primary key default gen_random_uuid(), module_key text not null, family_key text not null, indicator_key text not null, name text not null, description text, indicator_type text not null, visualization_type text not null, value_format text not null default 'number', calculation_type text not null, calculation_config jsonb not null default '{}'::jsonb, required_fields jsonb not null default '[]'::jsonb, optional_fields jsonb not null default '[]'::jsonb, availability_rules jsonb not null default '{}'::jsonb, default_visibility text not null default 'auto', available_for_dashboard boolean not null default true, available_for_reports boolean not null default true, is_system boolean not null default true, status text not null default 'active', sort_order integer not null default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(module_key, indicator_key)
);
create table if not exists public.native_indicator_calculation_logs (id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id) on delete cascade, indicator_definition_id uuid not null references public.native_indicator_definitions(id) on delete cascade, user_id uuid references auth.users(id) on delete set null, execution_type text not null default 'preview', availability_status text not null, records_considered integer not null default 0, result_preview jsonb, message text, created_at timestamptz not null default now());
alter table public.native_indicator_calculation_logs enable row level security;
create index if not exists idx_native_indicator_logs_tenant on public.native_indicator_calculation_logs(tenant_id, created_at desc);
drop trigger if exists set_native_indicator_definitions_updated_at on public.native_indicator_definitions; create trigger set_native_indicator_definitions_updated_at before update on public.native_indicator_definitions for each row execute function public.set_updated_at();
on conflict(module_key, indicator_key) do update set family_key=excluded.family_key,name=excluded.name,description=excluded.description,indicator_type=excluded.indicator_type,visualization_type=excluded.visualization_type,value_format=excluded.value_format,calculation_type=excluded.calculation_type,calculation_config=excluded.calculation_config,required_fields=excluded.required_fields,optional_fields=excluded.optional_fields,availability_rules=excluded.availability_rules,sort_order=excluded.sort_order,updated_at=now();
